def test_transaction_rollback():
    try:
        with db.transaction():
            db.insert('orders', {'total': 100})
            raise Exception('fail')
    except Exception:
        pass
    assert db.count('orders') == 0

def test_index_performance():
    explain = db.explain('SELECT * FROM orders WHERE user_id = 1')
    assert 'Index Scan' in explain

def test_foreign_key():
    with pytest.raises(IntegrityError):
        db.insert('orders', {'user_id': 99999, 'total': 50})

def test_stored_procedure():
    result = db.call('calculate_total', [1, 2, 3])
    assert result == 6

def test_connection_timeout():
    with pytest.raises(TimeoutError):
        db.connect(timeout=0.001)

def test_partition_pruning():
    explain = db.explain("SELECT * FROM logs WHERE created_at > '2024-01-01'")
    assert 'Partition' in explain

def test_query_timeout():
    with pytest.raises(QueryTimeout):
        db.execute('SELECT pg_sleep(60)', timeout=1)
